// refLabelHint shows a friendly fallback next to the id input. Keeps
// the empty case quiet ("none chosen") and the populated case useful
// ("currently #123 — click Choose to change").
func refLabelHint(value any) string {
	s := stringValue(value, nil)
	if s == "" || s == "0" {
		return "none chosen"
	}
	return "currently #" + s
}

// refPickerURL builds the GET endpoint that renders the picker modal,
// embedding the field key + tag filters so the picker rehydrates the
// right form input on click.
func refPickerURL(refKind string, f configurable.FieldDescriptor) string {
	base := "/design/picker/assets"
	if refKind == "entity-type" {
		base = "/design/picker/entities"
	}
	q := "?target_id=f-" + f.Key + "&target_label=f-" + f.Key + "-label"
	for _, t := range f.RefTags {
		q += "&tags=" + t
	}
	return base + q
}

