// ---- helpers (regular Go) --------------------------------------------------

func stringValue(value, defVal any) string {
	if value == nil {
		value = defVal
	}
	if value == nil {
		return ""
	}
	return fmt.Sprint(value)
}

func isTruthy(value, defVal any) bool {
	if value == nil {
		value = defVal
	}
	switch v := value.(type) {
	case bool:
		return v
	case string:
		b, _ := strconv.ParseBool(v)
		return b
	default:
		return false
	}
}

func formatFloat(v float64) string {
	return strconv.FormatFloat(v, 'f', -1, 64)
}

func stepValue(f configurable.FieldDescriptor) string {
	if f.Step != nil {
		return formatFloat(*f.Step)
	}
	return "any"
}

func vec2Component(value any, key string) string {
	if m, ok := value.(map[string]any); ok {
		return stringValue(m[key], nil)
	}
	return ""
}

func nestedValue(value any, key string) any {
	if m, ok := value.(map[string]any); ok {
		return m[key]
	}
	return nil
}

// prefixed returns a copy of child with its key prefixed by parent (using a
// dot). Used by nestedField so form names round-trip into nested JSON.
func prefixed(parent string, child configurable.FieldDescriptor) configurable.FieldDescriptor {
	out := child
	out.Key = parent + "." + child.Key
	return out
}

